/// Extract a display/snippet type from a schema's `type` keyword.
/// Handles both a single string and an array of types (nullable types);
/// for arrays, the first non-"null" type is preferred.
fn schema_type_of(schema: &serde_json::Value) -> Option<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => Some(s.clone()),
        Some(serde_json::Value::Array(types)) => {
            let mut first_null = None;
            for t in types.iter().filter_map(|t| t.as_str()) {
                if t == "null" {
                    first_null.get_or_insert(t);
                } else {
                    return Some(t.to_string());
                }
            }
            first_null.map(|s| s.to_string())
        }
        _ => None,
    }
}
