/// Schema composition keywords whose branches are merged for completions.
const COMPOSITION_KEYWORDS: [&str; 3] = ["allOf", "anyOf", "oneOf"];

/// Extract a display type from a schema's `type` keyword.
///
/// Handles both a single type string and an array of types (nullable types).
/// For arrays, the first non-"null" type is preferred so snippets and detail
/// text reflect the primary type (e.g. `["string", "null"]` → `"string"`).
fn schema_type_of(schema: &serde_json::Value) -> Option<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => Some(s.clone()),
        Some(serde_json::Value::Array(types)) => {
            let mut null_type = None;
            for t in types.iter().filter_map(|t| t.as_str()) {
                if t == "null" {
                    null_type.get_or_insert(t);
                } else {
                    return Some(t.to_string());
                }
            }
            null_type.map(|s| s.to_string())
        }
        _ => None,
    }
}

