/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, and `type` to generate value suggestions. Composition
/// branches (`allOf`/`anyOf`/`oneOf`) are merged and nullable types such as
/// `["string", "null"]` are handled. Duplicate suggestions are suppressed.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Recursively collect value suggestions from a schema and its composition
/// branches (`allOf`/`anyOf`/`oneOf`). `seen` holds JSON-formatted value keys
/// ("null", "true", "\"dark\"", ...) used to suppress duplicate suggestions
/// across branches and across suggestion kinds.
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Check for const.
    if let Some(const_val) = schema.get("const")
        && seen.insert(value_key(const_val))
    {
        suggestions.push(ValueSuggestion::Const(const_val.clone()));
    }

    // Check for enum.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            if seen.insert(value_key(val)) {
                suggestions.push(ValueSuggestion::Enum(val.clone()));
            }
        }
    }

    // Check for type-based suggestions. `type` may be a single string or an
    // array of types (e.g. ["string", "null"] for a nullable string).
    let types: Vec<&str> = match schema.get("type") {
        Some(serde_json::Value::String(s)) => vec![s.as_str()],
        Some(serde_json::Value::Array(arr)) => arr.iter().filter_map(|t| t.as_str()).collect(),
        _ => vec![],
    };
    for type_str in types {
        match type_str {
            "boolean" => {
                // Only suggest the true/false pair if neither was already
                // produced by an earlier branch or enum entry.
                let new_true = seen.insert("true".to_string());
                let new_false = seen.insert("false".to_string());
                if new_true && new_false {
                    suggestions.push(ValueSuggestion::Boolean);
                }
            }
            "null" => {
                if seen.insert("null".to_string()) {
                    suggestions.push(ValueSuggestion::Null);
                }
            }
            _ => {}
        }
    }

    // Recurse into composition branches (allOf/anyOf/oneOf).
    for keyword in COMPOSITION_KEYWORDS {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }
}

/// Stable dedup key for a suggested JSON value.
fn value_key(value: &serde_json::Value) -> String {
    serde_json::to_string(value).unwrap_or_default()
}

