#[test]
fn collect_values_no_suggestions() {
    let schema = serde_json::json!({
        "properties": {
            "name": { "type": "string" }
        }
    });
    let values = collect_values(&schema, &[], "name");
    assert!(values.is_empty());
}

#[test]
fn collect_properties_anyof_merge() {
    let schema = serde_json::json!({
        "anyOf": [
            {
                "properties": {
                    "name": { "type": "string" }
                },
                "required": ["name"]
            },
            {
                "properties": {
                    "age": { "type": "number" }
                }
            }
        ]
    });
    let props = collect_properties(&schema, &[]);
    assert_eq!(props.len(), 2);
    let name_prop = props.iter().find(|p| p.name == "name").unwrap();
    assert!(name_prop.required);
}

#[test]
fn collect_properties_oneof_merge() {
    let schema = serde_json::json!({
        "oneOf": [
            { "properties": { "cat": { "type": "string" } } },
            { "properties": { "dog": { "type": "string" } } }
        ]
    });
    let props = collect_properties(&schema, &[]);
    assert_eq!(props.len(), 2);
    assert!(props.iter().any(|p| p.name == "cat"));
    assert!(props.iter().any(|p| p.name == "dog"));
}

#[test]
fn collect_properties_dedup_across_branches() {
    let schema = serde_json::json!({
        "properties": {
            "shared": { "type": "string", "description": "top-level" }
        },
        "allOf": [
            { "properties": { "shared": { "type": "number" } } },
            { "properties": { "shared": { "type": "boolean" } } }
        ],
        "anyOf": [
            { "properties": { "shared": { "type": "null" } } }
        ]
    });
    let props = collect_properties(&schema, &[]);
    assert_eq!(props.len(), 1);
    // First occurrence wins.
    assert_eq!(props[0].schema_type.as_deref(), Some("string"));
}

#[test]
fn collect_properties_nullable_type() {
    let schema = serde_json::json!({
        "properties": {
            "nickname": { "type": ["string", "null"] },
            "maybe": { "type": ["null"] }
        }
    });
    let props = collect_properties(&schema, &[]);
    let nickname = props.iter().find(|p| p.name == "nickname").unwrap();
    assert_eq!(nickname.schema_type.as_deref(), Some("string"));
    let maybe = props.iter().find(|p| p.name == "maybe").unwrap();
    assert_eq!(maybe.schema_type.as_deref(), Some("null"));
}

#[test]
fn collect_properties_nested_in_anyof_branch() {
    let schema = serde_json::json!({
        "anyOf": [
            {
                "properties": {
                    "server": {
                        "type": "object",
                        "properties": {
                            "host": { "type": "string" }
                        }
                    }
                }
            }
        ]
    });
    let props = collect_properties(&schema, &["server".into()]);
    assert_eq!(props.len(), 1);
    assert_eq!(props[0].name, "host");
}

#[test]
fn collect_values_anyof_merges_enums_without_duplicates() {
    let schema = serde_json::json!({
        "properties": {
            "severity": {
                "anyOf": [
                    { "enum": ["low", "medium"] },
                    { "enum": ["medium", "high"] }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "severity");
    assert_eq!(values.len(), 3);
    assert!(matches!(&values[0], ValueSuggestion::Enum(v) if v == "low"));
    assert!(matches!(&values[1], ValueSuggestion::Enum(v) if v == "medium"));
    assert!(matches!(&values[2], ValueSuggestion::Enum(v) if v == "high"));
}

#[test]
fn collect_values_oneof_const_and_enum() {
    let schema = serde_json::json!({
        "properties": {
            "level": {
                "oneOf": [
                    { "const": 0 },
                    { "enum": [0, 1, 2] }
                ]
            }
        }
    });
    let values = collect_values(&schema, &[], "level");
    // const 0 dedups against enum 0.
    assert_eq!(values.len(), 3);
    assert!(matches!(&values[0], ValueSuggestion::Const(v) if v == &serde_json::json!(0)));
