/// Completion includes documentation from schema description.
#[tokio::test]
async fn completion_includes_documentation() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let name_item = items.iter().find(|i| i["label"] == "name").unwrap();

    let doc = name_item["documentation"]["value"].as_str().unwrap();
    assert!(
        doc.contains("The user's full name"),
        "expected description in documentation, got: {doc}"
    );
}

/// Count how many completion items carry the given label.
fn label_count(result: &serde_json::Value, label: &str) -> usize {
    result["items"]
        .as_array()
        .unwrap_or(&vec![])
        .iter()
        .filter(|item| item["label"] == label)
        .count()
}

/// Properties from allOf/anyOf branches are merged into root completions.
#[tokio::test]
async fn completion_merges_composed_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    for expected in ["legacy", "database", "shared", "variant"] {
        assert!(
            names.contains(&expected.to_string()),
            "expected '{expected}' from composed schema branches, got: {names:?}"
        );
    }
}

/// A property defined in multiple composition branches is suggested only once.
#[tokio::test]
async fn completion_composed_properties_have_no_duplicates() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    assert_eq!(
        label_count(&result, "shared"),
        1,
        "'shared' is defined in both allOf and anyOf branches but must appear once"
    );
}

/// Nested object completion navigates through an allOf branch at the root.
#[tokio::test]
async fn completion_nested_object_inside_composed_branch() {
    let mut client = TestClient::new();
    client.initialize().await;

    // {"$schema": "...", "database": {}}
    let content = doc_with_schema(r#""database": {}"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    // Cursor inside database {}
    let inner_brace = content.rfind('{').unwrap();
    let cursor_col = (inner_brace + 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"host".to_string()),
        "expected 'host' from allOf-defined 'database', got: {names:?}"
    );
    assert!(
        names.contains(&"port".to_string()),
        "expected 'port' from allOf-defined 'database', got: {names:?}"
    );
    assert!(
        !names.contains(&"name".to_string()),
        "root property 'name' must not appear in nested completions"
    );

    // 'host' is required inside database, so it sorts before 'port'.
    let items = result["items"].as_array().unwrap();
    let host = items.iter().find(|i| i["label"] == "host").unwrap();
    let port = items.iter().find(|i| i["label"] == "port").unwrap();
    assert!(
        host["sortText"].as_str().unwrap() < port["sortText"].as_str().unwrap(),
        "required 'host' should sort before optional 'port'"
    );
}

/// Enum values from anyOf branches are merged without duplicates.
#[tokio::test]
async fn completion_anyof_merges_enum_values_without_duplicates() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""severity": null"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"severity\": ").unwrap() + "\"severity\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    for expected in [r#""low""#, r#""medium""#, r#""high""#] {
        assert!(
            names.contains(&expected.to_string()),
            "expected {expected} in anyOf enum completions, got: {names:?}"
        );
    }
    // "medium" appears in both anyOf branches but must be suggested once.
    assert_eq!(
        label_count(&result, r#""medium""#),
        1,
        "'medium' must not be duplicated across anyOf branches"
    );
}

/// A nullable type (["string", "null"]) suggests null at the value position.
#[tokio::test]
async fn completion_nullable_type_suggests_null() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""nickname": "x""#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"nickname\": ").unwrap() + "\"nickname\": ".len();
