            label_count(&result, expected),
            1,
            "'{expected}' must appear exactly once"
        );
    }
}

/// Nullable property detail/snippet uses the primary (non-null) type.
#[tokio::test]
async fn completion_nullable_property_uses_primary_type() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

